package genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.service.VehicleModelService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/models") public class VehicleModelController { private final VehicleModelService service; public VehicleModelController(VehicleModelService service){this.service=service;} @GetMapping public List<VehicleModelResponse> list(@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(), filters, Set.of()); } @GetMapping("/{id}") public VehicleModelResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleModelResponse create(@RequestBody VehicleModelUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleModelResponse update(@PathVariable UUID id,@RequestBody VehicleModelUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
